        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new MultipleContrapartyReportsAdded();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[MultipleContrapartyReportsAdded](sbeTemplateId=");
            builder.Append(MultipleContrapartyReportsAdded.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(MultipleContrapartyReportsAdded.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != MultipleContrapartyReportsAdded.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(MultipleContrapartyReportsAdded.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != MultipleContrapartyReportsAdded.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(MultipleContrapartyReportsAdded.BlockLength);
            builder.Append("):");

            builder.Append("TargetDate=");
            builder.Append(this.TargetDate);
            builder.Append('|');
            builder.Append("NoReports=[");
            var noReports = this.NoReports;
            if (noReports.Count > 0)
            {
                var first = true;
                while (noReports.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    noReports.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
